// FiberServerOptions provides options for the Fiber server.
type FiberServerOptions struct {
	BaseURL     string
	Middlewares []MiddlewareFunc
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router fiber.Router, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, FiberServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router fiber.Router, si ServerInterface, options FiberServerOptions) {
	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	for _, m := range options.Middlewares {
		router.Use(fiber.Handler(m))
	}

	router.Get(options.BaseURL+"/peer-resources", wrapper.ListPeerResourceNames)

	router.Get(options.BaseURL+"/peer-resources/credentials", wrapper.ListPeerCredentials)

	router.Get(options.BaseURL+"/peer-resources/models", wrapper.ListPeerModels)

	router.Get(options.BaseURL+"/peer-resources/pets", wrapper.ListPeerPets)

	router.Post(options.BaseURL+"/peer-resources/pets", wrapper.AdoptPeerPet)

	router.Delete(options.BaseURL+"/peer-resources/pets/:id", wrapper.DeletePeerPet)

	router.Get(options.BaseURL+"/peer-resources/pets/:id", wrapper.GetPeerPet)

	router.Put(options.BaseURL+"/peer-resources/pets/:id", wrapper.PutPeerPet)

	router.Post(options.BaseURL+"/peer-resources/pets/:id/@feed", wrapper.FeedPeerPet)

	router.Post(options.BaseURL+"/peer-resources/pets/:id/@play", wrapper.PlayWithPeerPet)

	router.Post(options.BaseURL+"/peer-resources/pets/:id/@wash", wrapper.WashPeerPet)

	router.Get(options.BaseURL+"/peer-resources/rewards", wrapper.ListPeerRewards)

	router.Post(options.BaseURL+"/peer-resources/rewards/@claim", wrapper.ClaimPeerReward)

	router.Get(options.BaseURL+"/peer-resources/rewards/:id", wrapper.GetPeerReward)

	router.Get(options.BaseURL+"/peer-resources/voices", wrapper.ListPeerVoices)

	router.Get(options.BaseURL+"/peer-resources/wallet", wrapper.GetPeerWallet)

	router.Get(options.BaseURL+"/peer-resources/wallet-transactions", wrapper.ListPeerWalletTransactions)

	router.Get(options.BaseURL+"/peer-resources/wallet-transactions/:id", wrapper.GetPeerWalletTransaction)

	router.Get(options.BaseURL+"/peer-resources/workflows", wrapper.ListPeerWorkflows)

	router.Get(options.BaseURL+"/peer-resources/workspaces", wrapper.ListPeerWorkspaces)

	router.Get(options.BaseURL+"/play/voices/stream", wrapper.StreamPlayableVoices)

	router.Get(options.BaseURL+"/v1/voices", wrapper.ListClientVoices)

	router.Post(options.BaseURL+"/webrtc/offer", wrapper.CreateWebRTCOffer)

}

